@modal-padding: @component-padding;

atom-panel.modal {
  width: @font-size * 40;
  margin-left: @font-size * -20;
  color: @text-color;
  background-color: transparent;
  padding: @component-padding;

  atom-text-editor[mini] {
    margin-bottom: @component-padding;
  }

  .select-list ol.list-group,
  &.select-list ol.list-group {
    border: 1px solid @inset-panel-border-color;
    background-color: @inset-panel-background-color;

    &:empty {
      border: none;
      margin-top: 0;
    }

    li {
      padding: @modal-padding;
      border-bottom: 1px solid @overlay-border-color;
      overflow: hidden;
      line-height: 1.8;

      &:last-of-type {
        border-bottom: none;
      }

      .status.icon {
        float: right;
        margin-left: @component-icon-padding;
        &:before {
          margin-right: 0;
        }
      }

      &,
      pre {
        overflow: hidden;
      }
    }
  }

  .select-list .key-binding {
    margin-top: -1px;
    margin-left: @component-padding/2;
    margin-right: calc( -@component-padding/3 ~"+" 1px);
  }

  & > * {
    position: relative; // fixes stacking order
  }

  // Container
  &:before {
    content: "";
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    z-index: 0;
    background-color: @overlay-background-color;
    border-top: 1px solid hsla(0,0%,0%,.2);
    border-radius: 0 0 @component-border-radius*2 @component-border-radius*2;
    box-shadow: 0 6px 12px -2px hsla(0,0%,0%,.4);
  }

  // Backdrop
  // TODO: Add extra wrapper to translate individually or easier positioning

  &:after {
    content: "";
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    z-index: -1;
    background: @overlay-backdrop-color;
    -webkit-animation: overlay-fade .1s cubic-bezier(0.215, 0.61, 0.355, 1);
  }

  @-webkit-keyframes overlay-fade {
    0% { opacity: 0; }
    100% { opacity: 1; }
  }
}

//
// Clockhand
// -----------------------------------------------------------------------------
//
// ### Usage:
// Helpers for writing properties in clockhand manner.

.clockhand(@values, @prefix: ~"", @suffix: ~"", @collapse: false) {
    @l: length(@values);
    @pre: ~`'@{prefix}' ? '@{prefix}-' : ''`;
    @suf: ~`'@{suffix}' ? '-@{suffix}' : ''`;

    .map(1) {
        @top: extract(@values, 1);
        @right: @top;
        @bottom: @top;
        @left: @top;
    }
    .map(2) {
        @top: extract(@values, 1);
        @right: extract(@values, 2);
        @bottom: @top;
        @left: @right;
    }
    .map(3) {
        @top: extract(@values, 1);
        @right: extract(@values, 2);
        @bottom: extract(@values, 3);
        @left: @right;
    }
    .map(4) {
        @top: extract(@values, 1);
        @right: extract(@values, 2);
        @bottom: extract(@values, 3);
        @left: extract(@values, 4);
    }
    .map(@l);

    .reduce() when (@collapse) and not (@top = _) and not (@right = _)
        and not (@bottom = _) and not (@left = _) {
        .output() {
            @shorthand: @top;
        }
        .output() when not (@right = @top) {
            @shorthand: @top @right;
        }
        .output() when not (@bottom = @top) {
            @shorthand: @top @right @bottom;
        }
        .output() when not (@left = @right) {
            @shorthand: @top @right @bottom @left;
        }
        .output();
        @{prefix}@{suf}: @shorthand;
    }
    .reduce() when (default()) {
        .output() when not (@top = _) {
            @{pre}top@{suf}: @top;
        }
        .output() when not (@right = _) {
            @{pre}right@{suf}: @right;
        }
        .output() when not (@bottom = _) {
            @{pre}bottom@{suf}: @bottom;
        }
        .output() when not (@left = _) {
            @{pre}left@{suf}: @left;
        }
        .output();
    }

    .reduce();
}

.absolute(...) {
    position: absolute;
    .clockhand(@arguments);
}

.fixed(...) {
    position: fixed;
    .clockhand(@arguments);
}

.relative(...) {
    position: relative;
    .clockhand(@arguments);
}

.padding(...) {
    .clockhand(@arguments, padding, ~"", true);
}

.margin(...) {
    .clockhand(@arguments, margin, ~"", true);
}

.border-color(...) {
    .clockhand(@arguments, border, color, true);
}

.border-style(...) {
    .clockhand(@arguments, border, style, true);
}

.border-width(...) {
    .clockhand(@arguments, border, width, true);
}

